package frigolite

import (
	"testing"
)

// Auto-generated SQLite compatibility test suite
// Only includes SQL-related tests (C API and extension tests excluded)

// Auto-generated from 8_3_names.test
func TestSQLite_f_8_3_names(t *testing.T) {
	db := setupDB(t)
	var dbs []*DB
	dbs = append(dbs, db)
	_ = db.Query("PRAGMA cache_size=10;
    CREATE TABLE t1(x);
    INSERT INTO t1 VALUES(randomblob(20000));
    BEGIN;
    DELETE FROM t1;
    INSERT INTO t1 VALUES(randomblob(15000));")
	checkExecOK(t, db.Exec("ROLLBACK;
    SELECT length(x) FROM t1"))
	checkExecOK(t, db.Exec("COMMIT;
    SELECT length(x) FROM t1"))
	checkExecOK(t, db.Exec("COMMIT;
    SELECT sum(x) FROM t1;"))
	for _, d := range dbs { d.Close() }
}
// Auto-generated from affinity2.test
func TestSQLite_affinity2(t *testing.T) {
	db := setupDB(t)
	var dbs []*DB
	dbs = append(dbs, db)
	checkExecOK(t, db.Exec("CREATE TABLE t1(
    xi INTEGER,
    xr REAL,
    xb BLOB,
    xn NUMERIC,
    xt TEXT
  );
  INSERT INTO t1(rowid,xi,xr,xb,xn,xt) VALUES(1,1,1,1,1,1);
  INSERT INTO t1(rowid,xi,xr,xb,xn,xt) VALUES(2,'2','2','2','2','2');
  INSERT INTO t1(rowid,xi,xr,xb,xn,xt) VALUES(3,'03','03','03','03','03');"))
	checkQueryResult(t, db.Query("SELECT xi, typeof(xi) FROM t1 ORDER BY rowid;"), "{1 integer 2 integer 3 integer}")
	checkQueryResult(t, db.Query("SELECT xr, typeof(xr) FROM t1 ORDER BY rowid;"), "{1.0 real 2.0 real 3.0 real}")
	checkQueryResult(t, db.Query("SELECT xb, typeof(xb) FROM t1 ORDER BY rowid;"), "{1 integer 2 text 03 text}")
	checkQueryResult(t, db.Query("SELECT xn, typeof(xn) FROM t1 ORDER BY rowid;"), "{1 integer 2 integer 3 integer}")
	checkQueryResult(t, db.Query("SELECT rowid, xi==xt, xi==xb, xi==+xt FROM t1 ORDER BY rowid;"), "{1 1 1 1 2 1 1 1 3 1 1 1}")
	checkQueryResult(t, db.Query("SELECT rowid, xr==xt, xr==xb, xr==+xt FROM t1 ORDER BY rowid;"), "{1 1 1 1 2 1 1 1 3 1 1 1}")
	checkExecOK(t, db.Exec("CREATE TABLE ttt(c0, c1);
  CREATE INDEX ii ON ttt(CAST(c0 AS NUMERIC)); 
  INSERT INTO ttt VALUES('abc', '-1');"))
	checkQueryResult(t, db.Query("SELECT * FROM ttt WHERE CAST(c0 AS NUMERIC) > c1 GROUP BY rowid;"), "{abc -1}")
	checkExecOK(t, db.Exec("CREATE TABLE t3(a, b, c INTEGER);
  CREATE INDEX t3ac ON t3(a, c-1);
  INSERT INTO t3 VALUES(1, 1, 1);
  INSERT INTO t3 VALUES(2, 1, 0);
  INSERT INTO t3 VALUES(3, 1, 1);
  INSERT INTO t3 VALUES(4, 1, 0);
  INSERT INTO t3 VALUES(5, 1, 1);"))
	checkExecOK(t, db.Exec("DROP TABLE IF EXISTS t0;
  CREATE TABLE t0(c0 TEXT UNIQUE, c1);
  INSERT INTO t0(c0) VALUES (-1);
  SELECT quote(- x'ce'), quote(t0.c0), quote(- x'ce' >= t0.c0) FROM t0;"))
	checkQueryResult(t, db.Query("SELECT * FROM t0 WHERE - x'ce' >= t0.c0;"), "{-1 {}}")
	checkQueryResult(t, db.Query("SELECT quote(+-+x'ce'), quote(t0.c0), quote(+-+x'ce' >= t0.c0) FROM t0;"), "{0 '-1' 1}")
	checkQueryResult(t, db.Query("SELECT * FROM t0 WHERE +-+x'ce' >= t0.c0;"), "{-1 {}}")
	checkQueryResult(t, db.Query("SELECT quote(- 'ce'), quote(t0.c0), quote(- 'ce' >= t0.c0) FROM t0;"), "{0 '-1' 1}")
	checkQueryResult(t, db.Query("SELECT * FROM t0 WHERE - 'ce' >= t0.c0;"), "{-1 {}}")
	checkQueryResult(t, db.Query("SELECT quote(+-+'ce'), quote(t0.c0), quote(+-+'ce' >= t0.c0) FROM t0;"), "{0 '-1' 1}")
	checkQueryResult(t, db.Query("SELECT 1 FROM t0 WHERE 3175546974276630385 < c0;"), "{1}")
	for _, d := range dbs { d.Close() }
}
// Auto-generated from affinity3.test
func TestSQLite_affinity3(t *testing.T) {
	db := setupDB(t)
	var dbs []*DB
	dbs = append(dbs, db)
	checkExecOK(t, db.Exec("CREATE TABLE customer (id INT PRIMARY KEY);
  CREATE TABLE apr (id INT PRIMARY KEY, apr REAL);

  CREATE VIEW v1 AS
  SELECT c.id, i.apr
  FROM customer c
  LEFT JOIN apr i ON i.id=c.id;

  CREATE VIEW v1rj AS
  SELECT c.id, i.apr
  FROM apr i
  RIGHT JOIN customer c ON i.id=c.id;

  CREATE VIEW v2 AS
  SELECT c.id, v1.apr
  FROM customer c
  LEFT JOIN v1 ON v1.id=c.id;

  CREATE VIEW v2rj AS
  SELECT c.id, v1.apr
  FROM v1 RIGHT JOIN customer c ON v1.id=c.id;

  CREATE VIEW v2rjrj AS
  SELECT c.id, v1rj.apr
  FROM v1rj RIGHT JOIN customer c ON v1rj.id=c.id;

  INSERT INTO customer (id) VALUES (1);
  INSERT INTO apr (id, apr) VALUES (1, 12);
  INSERT INTO customer (id) VALUES (2);
  INSERT INTO apr (id, apr) VALUES (2, 12.01);"))
	checkQueryResult(t, db.Query("PRAGMA automatic_index=ON;
  SELECT id, (apr / 100), typeof(apr) apr_type  FROM v1;"), "{1 0.12 real 2 0.1201 real}")
	checkQueryResult(t, db.Query("PRAGMA automatic_index=ON;
  SELECT id, (apr / 100), typeof(apr) apr_type  FROM v1rj;"), "{1 0.12 real 2 0.1201 real}")
	checkQueryResult(t, db.Query("SELECT id, (apr / 100), typeof(apr) apr_type  FROM v2;"), "{1 0.12 real 2 0.1201 real}")
	checkQueryResult(t, db.Query("SELECT id, (apr / 100), typeof(apr) apr_type  FROM v2rj;"), "{1 0.12 real 2 0.1201 real}")
	checkQueryResult(t, db.Query("SELECT id, (apr / 100), typeof(apr) apr_type  FROM v2rjrj;"), "{1 0.12 real 2 0.1201 real}")
	checkQueryResult(t, db.Query("PRAGMA automatic_index=OFF;
  SELECT id, (apr / 100), typeof(apr) apr_type  FROM v1;"), "{1 0.12 real 2 0.1201 real}")
	checkQueryResult(t, db.Query("SELECT id, (apr / 100), typeof(apr) apr_type  FROM v1rj;"), "{1 0.12 real 2 0.1201 real}")
	checkExecOK(t, db.Exec("CREATE TABLE map_integer (id INT, name);
  INSERT INTO map_integer VALUES(1,'a');
  CREATE TABLE map_text (id TEXT, name);
  INSERT INTO map_text VALUES('4','e');
  CREATE TABLE data (id TEXT, name);
  INSERT INTO data VALUES(1,'abc');
  INSERT INTO data VALUES('4','xyz');
  CREATE VIEW idmap as
      SELECT * FROM map_integer
      UNION SELECT * FROM map_text;
  CREATE TABLE mzed AS SELECT * FROM idmap;"))
	checkQueryResult(t, db.Query("PRAGMA automatic_index=ON;
  SELECT * FROM data JOIN idmap USING(id);"), "{4 xyz e}")
	checkQueryResult(t, db.Query("PRAGMA automatic_index=OFF;
  SELECT * FROM data JOIN idmap USING(id);"), "{4 xyz e}")
	for _, d := range dbs { d.Close() }
}
